INSERT INTO learning_blocks (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('c++', 31, 'beginner', 1, 'for 循环', '["循环","for"]', '用于已知迭代次数的循环结构', 'for 循环是 C++ 中最常用的循环之一。\n语法为：for (初始化表达式; 条件表达式; 更新表达式) { 循环体 }。\n它首先执行初始化，然后检查条件，如果为真则执行循环体，之后执行更新表达式，再次检查条件，直到条件为假。\n适用于循环次数已知的情况。', '["for (int i = 0; i < 5; i++) {\\n    cout << i << \\" \\";\\n}"]', '["0 1 2 3 4 "]'),
('c++', 32, 'beginner', 1, 'while 循环', '["循环","while"]', '在条件为真时重复执行循环体', 'while 循环在条件表达式为真时执行循环体。\n语法为：while (条件) { 循环体 }。\n它先检查条件，如果为真则执行循环体，然后再次检查条件。\n适用于循环次数未知但条件可判断的情况。', '["int i = 0;\\nwhile (i < 5) {\\n    cout << i << \\" \\";\\n    i++;\\n}"]', '["0 1 2 3 4 "]'),
('c++', 33, 'beginner', 1, 'do-while 循环', '["循环","do-while"]', '至少执行一次循环体，然后在条件为真时重复', 'do-while 循环先执行循环体，然后检查条件。\n语法为：do { 循环体 } while (条件);。\n它至少执行一次循环体，然后如果条件为真则继续循环。\n适用于需要先执行后检查的情况。', '["int i = 0;\\ndo {\\n    cout << i << \\" \\";\\n    i++;\\n} while (i < 5);"]', '["0 1 2 3 4 "]'),
('c++', 34, 'beginner', 1, 'break 语句', '["循环控制","break"]', '用于立即退出循环', 'break 语句用于在循环中立即终止循环，跳出循环体。\n它通常与条件语句结合使用，当满足某些条件时提前结束循环。', '["for (int i = 0; i < 10; i++) {\\n    if (i == 5) {\\n        break;\\n    }\\n    cout << i << \\" \\";\\n}"]', '["0 1 2 3 4 "]'),
('c++', 35, 'beginner', 1, 'continue 语句', '["循环控制","continue"]', '用于跳过当前循环迭代的剩余部分', 'continue 语句用于在循环中跳过当前迭代的剩余代码，直接进行下一次迭代。\n它不会终止循环，只是跳过本次循环体中的后续语句。', '["for (int i = 0; i < 5; i++) {\\n    if (i == 2) {\\n        continue;\\n    }\\n    cout << i << \\" \\";\\n}"]', '["0 1 3 4 "]');